INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, "", "", 11, "", "朝、一人でレッスンしてたら\nお散歩してた人から\n『いつも頑張ってるね』って\n言ってもらえたんです", 1, 1060022, 6, 1, 112411);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", "", "", 91, "", "", "", 1060023, 6, "", 0);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, "", "", 3, 0, "omp_talk_thinking", "", 1060024, 6, "", 112411);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (0, "", "", 21, "", "vo_omp_7006_004", "", 1060025, 6, 0, "vo_omp_7006");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, "", "", 11, "", "あの人にとっては何気ない\n一言だったのかも知れないですけど\n私にはそれがとてもうれしくて", 1, 1060026, 6, 1, 112411);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", "", "", 91, "", "", "", 1060027, 6, "", 0);
