INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, "", "", 11, "", "今思うと…最初のゲリラLIVEは\nほんとうにいっぱいいっぱいでしたね", 1, 1070016, 7, 1, 112411);
