INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (0, "", "", 21, "", "vo_omp_7007_002", "", 1070025, 7, 0, "vo_omp_7007");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, "", "", 11, "", "ペコリーヌさまの場合は、\n空腹で締め付けられていた\n可能性もありますが…", 1, 1070026, 7, 1, 105931);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", "", "", 91, "", "", "", 1070027, 7, "", 0);
