INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1, "", "", 3, 0, "omp_talk_worry", "", 1070034, 7, "", 112611);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (0, "", "", 21, "", "vo_omp_7007_004", "", 1070035, 7, 0, "vo_omp_7007");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (10, "", "", 11, "", "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", 1, 1070036, 7, 1, 112611);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", "", "", 91, "", "", "", 1070037, 7, "", 0);
